// Wire-format freeze test.
//
// These assertions pin the parts of the A2A extension that travel on the wire
// and therefore MUST NOT change without a conscious version decision (see
// VERSIONING.md): the extension URI, the activation header it carries, the
// versioned metadata keys, the VC formats, and the engine-error -> A2A-error
// mapping shape. A change here that is intentional should bump the extension
// URI (`.../a2a/v2`) and update this snapshot in the same commit; an accidental
// change should fail CI loudly. Adding a brand-new key still requires editing
// this test, which is the point — it forces the wire surface to be reviewed.

import { test } from "node:test";
import assert from "node:assert/strict";
import { readFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import path from "node:path";

import {
  EXTENSION_URI,
  A2A_VERSION,
  A2A_MEDIA_TYPE,
  VC_FORMATS,
  metadataKeys,
  metadataKey,
  extensionHeaderIncludes,
  mapEngineDecisionToA2aError,
} from "portauth-a2a";

const V1_URI = "https://kyndryl-open-source.github.io/aiagent-portable-authorization/a2a/v1";
const schemasDir = path.resolve(fileURLToPath(import.meta.url), "../../schemas");

test("extension URI is frozen at v1", () => {
  assert.equal(EXTENSION_URI, V1_URI);
});

test("protocol-level constants are frozen", () => {
  assert.equal(A2A_VERSION, "1.0");
  assert.equal(A2A_MEDIA_TYPE, "application/a2a+json");
});

test("VC formats are frozen", () => {
  assert.deepEqual([...VC_FORMATS], ["tier1-jwt", "tier2-x509-jwt", "tier3-vc-jose"]);
});

test("metadata keys are frozen (exact key set and URI-prefixed values)", () => {
  // Adding/removing/renaming any of these is a wire change. Update only with a
  // version decision recorded in VERSIONING.md.
  assert.deepEqual({ ...metadataKeys }, {
    vc: `${V1_URI}/vc`,
    vcFormat: `${V1_URI}/vcFormat`,
    presenterId: `${V1_URI}/presenterId`,
    proofOfPossession: `${V1_URI}/proofOfPossession`,
    idempotencyKey: `${V1_URI}/idempotencyKey`,
    delegationChain: `${V1_URI}/delegationChain`,
  });
  assert.equal(metadataKey("vc"), `${V1_URI}/vc`);
});

test("activation header carries the v1 URI", () => {
  // The receiver activates the extension via `A2A-Extensions: <EXTENSION_URI>`.
  assert.equal(extensionHeaderIncludes(EXTENSION_URI), true);
  assert.equal(extensionHeaderIncludes(`other, ${EXTENSION_URI}`), true);
  assert.equal(extensionHeaderIncludes("https://example.com/other"), false);
});

test("published JSON schemas reference the same v1 URI", () => {
  const metadata = JSON.parse(readFileSync(path.join(schemasDir, "metadata.schema.json"), "utf8"));
  assert.equal(metadata.$id, `${V1_URI}/metadata.schema.json`);

  const card = JSON.parse(readFileSync(path.join(schemasDir, "agent-card-extension.schema.json"), "utf8"));
  assert.equal(card.$id, `${V1_URI}/agent-card-extension.schema.json`);
  assert.equal(card.properties.uri.const, V1_URI);
});

test("engine-error to A2A-error mapping is frozen for the core reasons", () => {
  // The receiver and clients depend on these (status, reason) pairs. New engine
  // errors may be added, but these established mappings must not move.
  const cases = [
    ["authorization_denied", 403, "PORTAUTH_AUTHORIZATION_DENIED"],
    ["validation_error", 400, "PORTAUTH_INVALID_REQUEST"],
    ["credential_incomplete", 422, "PORTAUTH_CREDENTIAL_INCOMPLETE"],
    ["signature_invalid", 401, "PORTAUTH_SIGNATURE_INVALID"],
    ["credential_expired", 401, "PORTAUTH_CREDENTIAL_EXPIRED"],
    ["proof_of_possession_failed", 401, "PORTAUTH_PROOF_OF_POSSESSION_FAILED"],
  ];
  for (const [engineError, httpStatus, reason] of cases) {
    const { httpStatus: status, body } = mapEngineDecisionToA2aError({ error: engineError });
    assert.equal(status, httpStatus, `status for ${engineError}`);
    assert.equal(extractReason(body), reason, `reason for ${engineError}`);
  }
});

// The google.rpc.Status shape nests the PortAuth reason; pull it out without
// over-coupling the test to the exact envelope layout.
function extractReason(body) {
  const json = JSON.stringify(body);
  const match = json.match(/PORTAUTH_[A-Z_]+/);
  return match ? match[0] : null;
}
